class Solution {
    public int minChanges(int[] nums, int k) {
        int n = nums.length;
        int[] prefixXOR = new int[n + 1];
        for (int i = 0; i < n; i++) {
            prefixXOR[i + 1] = prefixXOR[i] ^ nums[i];
        }
        int[] count = new int[1 << 10];
        int same = 0;
        for (int i = k; i <= n; i++) {
            int xor = prefixXOR[i] ^ prefixXOR[i - k];
            if (xor == 0) {
                same++;
            } else {
                count[xor]++;
            }
        }
        int max = same;
        for (int i = 0; i < (1 << 10); i++) {
            max = Math.max(max, count[i]);
        }
        return n - (max + same);
    }
}
```
